mapper.update:
update tutoring_request
set status = #{target}, update_by = #{updateBy}, update_time = sysdate()
where request_id = #{requestId} and status = #{current}

update tutoring_request
set schedule_text = #{scheduleText}, update_by = #{updateBy}, update_time = sysdate()
where request_id = #{requestId}

update tutoring_match
set status = #{target}, update_by = #{updateBy}, update_time = sysdate()
where match_id = #{matchId} and status = #{current}

update tutoring_match
set status = '4', cancel_reason = #{cancelReason}, update_by = #{updateBy}, update_time = sysdate()
where match_id = #{matchId} and status = #{current}

update tutoring_match
set reschedule_text = #{rescheduleText}, update_by = #{updateBy}, update_time = sysdate()
where match_id = #{matchId}

mapper.select:
select
  (select count(1) from tutoring_request) leadCount,
  (select count(1) from tutoring_match where status in ('1', '2')) dealCount,
  coalesce((select round(count(1) * 100.0 / nullif((select count(1) from tutoring_request), 0), 1)
            from tutoring_match where status in ('1', '2')), 0) conversionRate,
  (select count(1) from (
     select publisher_id from tutoring_request group by publisher_id having count(1) > 1
   ) repeat_clients) repeatClients,
  (select coalesce(sum(case when status = '1' then amount
                            when status = '3' then amount - coalesce(refund_amount, 0)
                            else 0 end), 0)
     from tutoring_payment where status in ('1', '3')) gmv,
  (select coalesce(sum(case when status in ('1', '3') then platform_fee else 0 end), 0)
     from tutoring_payment where status in ('1', '3')) platformRevenue,
  (select count(distinct tutor_id) from tutoring_match
     where status in ('1', '2') and update_time >= date_sub(sysdate(), interval 30 day)) activeTutors,
  coalesce((select round(count(1) * 100.0 / nullif((select count(1) from tutoring_match), 0), 1)
            from tutoring_complaint), 0) complaintRate,
  (select coalesce(round(avg(timestampdiff(hour, create_time, update_time)), 1), 0)
     from tutoring_ticket where status in ('1', '2') and update_time is not null) avgTicketHours

select count(1)
from tutoring_lesson l
join tutoring_match m on m.match_id = l.match_id
where m.tutor_id = #{tutorId}
  and l.lesson_date = #{lessonDate}
  and l.start_time is not null
  and l.end_time is not null
  and l.start_time < #{endTime}
  and l.end_time > #{startTime}

select from tutoring_payment p join tutoring_match m on m.match_id = p.match_id join tutoring_request r on r.request_id = m.request_id left join sys_user payer on payer.user_id = p.payer_id left join sys_user tutor on tutor.user_id = m.tutor_id where 1 = 1
and p.status = #{status}
order by p.status asc, p.create_time desc, p.payment_id desc

select count(1) from tutoring_payment
where match_id = #{matchId} and status = '1'
and payment_id != #{paymentId}

select 
from tutoring_finance_ledger l
left join sys_user u on u.user_id = l.user_id
left join tutoring_match m on m.match_id = l.match_id
left join tutoring_request r on r.request_id = m.request_id
where 1 = 1

    and l.biz_type = #{bizType}


    and l.match_id = #{matchId}


    and l.status = #{status}

order by l.create_time desc, l.ledger_id desc

select b.blacklist_id, b.user_id, u.nick_name user_name, b.reason, b.status, b.handle_by, b.handle_time, b.create_by, b.create_time from tutoring_blacklist b left join sys_user u on u.user_id = b.user_id where 1 = 1
and b.user_id = #{userId}
and b.status = #{status}
order by b.status desc, b.create_time desc, b.blacklist_id desc

select f.followup_id, f.match_id, r.subject, publisher.nick_name publisher_name, tutor.nick_name tutor_name, f.content, f.next_action, f.next_time, f.status, f.create_by, f.create_time from tutoring_followup f join tutoring_match m on m.match_id = f.match_id join tutoring_request r on r.request_id = m.request_id left join sys_user publisher on publisher.user_id = r.publisher_id left join sys_user tutor on tutor.user_id = m.tutor_id where 1 = 1
and f.match_id = #{matchId}
and f.status = #{status}
order by f.status asc, f.next_time asc, f.create_time desc, f.followup_id desc

select notification_id notificationId, user_id userId, title, content, channel, template_code templateCode, send_status sendStatus, read_status readStatus, create_time createTime from tutoring_notification where user_id = #{userId}
and read_status = #{readStatus}
and title like concat('%', #{title}, '%')
order by create_time desc limit 100
